import{_ as e,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"36. Right To Disconnect","description":"","frontmatter":{"title":"36. Right To Disconnect","eba":"Mental Health Services 2024-2028","topics":["right-to-disconnect"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/allowances/36-right-to-disconnect.md","filePath":"ebas/mental-health/common-terms/allowances/36-right-to-disconnect.md"}'),r={name:"ebas/mental-health/common-terms/allowances/36-right-to-disconnect.md"};function s(i,t,c,p,h,l){return o(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="_36-right-to-disconnect" tabindex="-1">36. Right To Disconnect <a class="header-anchor" href="#_36-right-to-disconnect" aria-label="Permalink to &quot;36. Right To Disconnect&quot;">​</a></h1><p>This clause is to be read in conjunction with <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/95A-right-to-disconnect-supplementary-roster.html">clause 95A</a>.</p><p>(1) Subject to the provisions of this Agreement, the general protections in Part 3-1 of the Act prohibits an employer taking adverse action against an employee because of the employee’s right to disconnect under section 333M of the Act.</p><p>(2) An employee may refuse to monitor, read or respond to contact, or attempted contact, from an employer outside of the employee&#39;s working hours unless the refusal is unreasonable.</p><p>(3) An employee may refuse to monitor, read or respond to contact, or attempted contact, from a third party if the contact or attempted contact relates to their work and is outside of the employee&#39;s working hours unless the refusal is unreasonable.</p><p>(4) Without limiting the matters that may be taken into account in determining whether a refusal is unreasonable for the purposes of subsections (1) and (2), the following must be taken into account:</p><p><strong>(a)</strong> the reason for the contact or attempted contact</p><p><strong>(b)</strong> how the contact or attempted contact is made and the level of disruption the contact or attempted contact causes the employee;</p><p><strong>(c)</strong> the extent to which the employee is compensated:</p><p><strong>(i)</strong> to remain available to perform work during the period in which the contact or attempted contact is made; or</p><p><strong>(ii)</strong> for working additional hours outside of the employee&#39;s ordinary hours of work;</p><p><strong>(d)</strong> the nature of the employee&#39;s role and the employee&#39;s level of responsibility;</p><p><strong>(e)</strong> the employee&#39;s personal circumstances (including family or caring responsibilities).</p><p>Note: For the purposes of paragraph (c), the extent to which an employee is compensated includes any non - monetary compensation.</p><p>(4) For the avoidance of doubt, an employee&#39;s refusal to monitor, read or respond to contact, or attempted contact, from their employer, or from a third party if the contact or attempted contact relates to their work, will be unreasonable if the contact or attempted contact is required under a law of the Commonwealth, a State or a Territory.</p><p>(5) The dispute resolution procedure in this Agreement will apply to disputes arising in relation to this clause.</p><p>Plain language terms: after hours contact, out of hours, work-life boundary, no phone calls after work.</p>',17)])])}const u=e(r,[["render",s]]);export{d as __pageData,u as default};
